def lexical_analysis(source_code):
 tokens = []
 for char in source_code:
 if char.isalpha():
 tokens.append(('IDENTIFIER', char))
 elif char.isdigit():
 tokens.append(('LITERAL', char))
 return tokens

source_code = 'int x = 5;'
tokens = lexical_analysis(source_code)
print(tokens)

